import{_ as t,c as a,o,a1 as i}from"./chunks/framework.DDNAyvCW.js";const r="/assets/chattoai1.DzEei9pr.png",n="/assets/chattoai2.euuUtSg0.png",g=JSON.parse('{"title":"Chat to AI","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/chattoai/index.md","filePath":"docs/terminal/chattoai/index.md"}'),d={name:"docs/terminal/chattoai/index.md"};function s(l,e,c,h,u,m){return o(),a("div",null,e[0]||(e[0]=[i('<h1 id="chat-to-ai" tabindex="-1">Chat to AI <a class="header-anchor" href="#chat-to-ai" aria-label="Permalink to &quot;Chat to AI&quot;">​</a></h1><p>Chat to AI lets you interact with AI directly from the terminal to generate commands, troubleshoot issues, and plan complex tasks.</p><p>Chaterm provides two distinct AI interaction modes. Choose the one that fits your task:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Shortcut</th><th>Best For</th></tr></thead><tbody><tr><td>AI Command Dialog</td><td><code>Cmd + K</code> / <code>Ctrl + K</code></td><td>Quick, single-command generation</td></tr><tr><td>AI Sidebar</td><td><code>Cmd + L</code> / <code>Ctrl + L</code></td><td>Complex tasks requiring context and conversation</td></tr></tbody></table><h2 id="mode-1-ai-command-dialog-cmd-k-ctrl-k" tabindex="-1">Mode 1: AI Command Dialog (<code>Cmd + K</code> / <code>Ctrl + K</code>) <a class="header-anchor" href="#mode-1-ai-command-dialog-cmd-k-ctrl-k" aria-label="Permalink to &quot;Mode 1: AI Command Dialog (`Cmd + K` / `Ctrl + K`)&quot;">​</a></h2><p>A lightweight popup that turns a plain-language request into a ready-to-run command. Use it when you know <em>what</em> you want to do but not the exact syntax.</p><p><img src="'+r+'" alt=""></p><h3 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li>Press <code>Cmd + K</code> (macOS) or <code>Ctrl + K</code> (Windows/Linux) while in the terminal.</li><li>Type what you want to accomplish in plain language.</li><li>AI generates the corresponding command.</li><li>Review the command, then press Enter to insert it into the terminal.</li></ol><h3 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h3><ul><li>You need a command but cannot remember the flags or syntax.</li><li>You want to perform a single, straightforward operation.</li><li>You are looking up how to use a specific tool.</li></ul><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><table tabindex="0"><thead><tr><th>You Type</th><th>AI Generates</th></tr></thead><tbody><tr><td>&quot;Find all <code>.log</code> files larger than 100MB&quot;</td><td><code>find / -name &quot;*.log&quot; -size +100M</code></td></tr><tr><td>&quot;Show disk usage sorted by size&quot;</td><td><code>du -sh /* | sort -rh</code></td></tr><tr><td>&quot;Restart the nginx service&quot;</td><td><code>sudo systemctl restart nginx</code></td></tr><tr><td>&quot;Compress the <code>/var/log</code> directory&quot;</td><td><code>tar -czf /tmp/var-log-backup.tar.gz /var/log</code></td></tr></tbody></table><h2 id="mode-2-ai-sidebar-cmd-l-ctrl-l" tabindex="-1">Mode 2: AI Sidebar (<code>Cmd + L</code> / <code>Ctrl + L</code>) <a class="header-anchor" href="#mode-2-ai-sidebar-cmd-l-ctrl-l" aria-label="Permalink to &quot;Mode 2: AI Sidebar (`Cmd + L` / `Ctrl + L`)&quot;">​</a></h2><p>A persistent sidebar that reads your terminal&#39;s context -- output history, working directory, and environment -- and lets you have a multi-turn conversation with AI. Use it when you need to plan, troubleshoot, or iterate.</p><p><img src="'+n+'" alt=""></p><h3 id="steps-1" tabindex="-1">Steps <a class="header-anchor" href="#steps-1" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li>Press <code>Cmd + L</code> (macOS) or <code>Ctrl + L</code> (Windows/Linux) while in the terminal.</li><li>The sidebar opens and automatically captures the current terminal context.</li><li>Describe your task or ask a question.</li><li>AI analyzes the context and responds with suggestions or commands.</li><li>Continue the conversation to refine the plan, then execute commands step by step.</li></ol><h3 id="what-context-ai-reads" tabindex="-1">What Context AI Reads <a class="header-anchor" href="#what-context-ai-reads" aria-label="Permalink to &quot;What Context AI Reads&quot;">​</a></h3><ul><li>Current terminal output and scrollback history.</li><li>Current working directory.</li><li>Terminal session environment information.</li></ul><h3 id="when-to-use-1" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use-1" aria-label="Permalink to &quot;When to Use&quot;">​</a></h3><ul><li>A task requires multiple steps (e.g., deploying an application).</li><li>You need to troubleshoot an error visible in the terminal output.</li><li>You want to discuss trade-offs before executing commands.</li><li>You need AI to understand what just happened in the session.</li></ul><h3 id="example-troubleshooting-a-failed-service" tabindex="-1">Example: Troubleshooting a Failed Service <a class="header-anchor" href="#example-troubleshooting-a-failed-service" aria-label="Permalink to &quot;Example: Troubleshooting a Failed Service&quot;">​</a></h3><p><strong>Before (manual):</strong> You see <code>nginx.service: Failed</code> in the terminal. You manually run <code>journalctl</code>, read logs, edit config files, and restart -- guessing along the way.</p><p><strong>After (with AI Sidebar):</strong></p><ol><li>Press <code>Cmd + L</code> to open the sidebar. AI sees the error output automatically.</li><li>Type: &quot;Why did nginx fail to start?&quot;</li><li>AI reads the terminal output, identifies the config syntax error, and suggests the fix.</li><li>You apply the fix and ask AI to verify: &quot;Check if nginx config is valid now.&quot;</li><li>AI generates <code>nginx -t</code>, you run it, and AI confirms success.</li></ol><h2 id="shortcuts" tabindex="-1">Shortcuts <a class="header-anchor" href="#shortcuts" aria-label="Permalink to &quot;Shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>Open AI Command Dialog</td><td><code>Cmd + K</code></td><td><code>Ctrl + K</code></td></tr><tr><td>Open / Toggle AI Sidebar</td><td><code>Cmd + L</code></td><td><code>Ctrl + L</code></td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li><strong>Be specific.</strong> Instead of &quot;fix this&quot;, say &quot;the nginx config on line 42 has a syntax error -- suggest a fix.&quot;</li><li><strong>Use the sidebar for multi-step work.</strong> Let AI plan the steps, then execute them one at a time.</li><li><strong>Save useful commands.</strong> After AI generates a command you will reuse, save it as a <a href="/docs/terminal/snippets/">Command Snippet</a> for one-click execution later.</li><li><strong>Review before executing.</strong> Always read AI-generated commands before running them, especially on production servers.</li></ul><div class="warning custom-block"><p class="custom-block-title">Security Notice</p><ul><li>Do not execute AI-generated commands that could cause data loss without reviewing them first.</li><li>For sensitive operations, always confirm manually.</li><li>Verify destructive commands in a test environment before running them in production.</li></ul></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/docs/ai/dialogs/">AI Dialogs</a> -- more details on AI dialog configuration and capabilities.</li><li><a href="/docs/terminal/snippets/">Command Snippets</a> -- save and reuse commands generated by AI.</li></ul>',33)]))}const b=t(d,[["render",s]]);export{g as __pageData,b as default};
